def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = np.inf
        else:
            score = 0
            temp = ratio
            for _ in range(5):
                if temp >= 1:
                    score += 1000
                else:
                    score += (1 - temp) ** 2 * 10
                temp *= 2
            if cap % 2 == 0:
                score *= 0.9
            elif cap % 3 == 0:
                score *= 0.95
            if cap > 50:
                score -= (cap - 50) * 0.05
            priorities[i] = score if score > 0 else 0
    return priorities
